import React from 'react';
import './Contact.css';
import { HiOutlineMail } from "react-icons/hi";
import { CiLinkedin } from "react-icons/ci";

function Contact() {
  return (
    <section id="contact">
      <h1>Contact Me</h1>
      <p>If you would like to connect, discuss a project, or have any questions, please feel free to reach out:</p>

      <div className="contact-details">
        <p>
          <HiOutlineMail className="contact-icon" />
          <strong>Email:</strong> <a href="mailto:yourname@example.com">yourname@example.com</a>
        </p>
        <p>
          <CiLinkedin className="contact-icon" />
          <strong>LinkedIn:</strong> <a href="https://linkedin.com/in/ruman-i" target="_blank" rel="noopener noreferrer">linkedin.com/in/ruman-i</a>
        </p>
      </div>

      <p className="thank-you-message">Thank you for browsing my website and for taking the time to scroll down!</p>
    </section>
  );
}

export default Contact;
